diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..400382bfc92b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1862,6 +1862,7 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   if (Value *V = simplifySubInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -2084,7 +2085,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
       return BinaryOperator::CreateNeg(Builder.CreateXor(A, B));
   }

-  // (sub (or A, B), (xor A, B)) --> (and A, B)
+  // (sub (or A, B) (xor A, B)) --> (and A, B)
   {
     Value *A, *B;
     if (match(Op1, m_Xor(m_Value(A), m_Value(B))) &&
@@ -2298,9 +2299,23 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
         I, Builder.CreateIntrinsic(Intrinsic::ctpop, {I.getType()},
                                    {Builder.CreateNot(X)}));

+  // 64 - ((71 - x) & -8) -> x & 120
+  // TODO: Generalize this pattern for other constants.
+  {
+    Value *X;
+    const APInt *C1, *C2, *C3;
+    if (match(Op0, m_APInt(C1)) &&
+        match(Op1, m_And(m_Sub(m_APInt(C2), m_Value(X)), m_APInt(C3)))) {
+      if (C1->getBitWidth() == 64 && *C1 == 64 && *C2 == 71 && *C3 == -8) {
+        return replaceInstUsesWith(I, Builder.CreateAnd(X, APInt(64, 120)));
+      }
+    }
+  }
+
   return TryToNarrowDeduceFlags();
 }

+
